class Board:
    def __init__(self):
        self.setup_board()

    def setup_board(self):
        self.pieces = {}
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 0 and not (row < 3 or row > 4):
                    if row < 3:
                        self.pieces[(chr(col + 97) + str(row + 1))] = Piece("White", True)
                    elif row > 4:
                        self.pieces[(chr(col + 97) + str(row + 1))] = Piece("Black", True)

    def move_piece(self, start_pos, end_pos, player):
        if start_pos in self.pieces and end_pos not in self.pieces:
            piece = self.pieces[start_pos]
            if piece.color == player.color and piece.move(start_pos, end_pos):
                del self.pieces[start_pos]
                self.pieces[end_pos] = piece
                return True
        return False

    def __str__(self):
        board_str = "  a b c d e f g h\n"
        for row in range(8):
            board_str += str(row + 1) + "| "
            for col in range(8):
                pos = chr(col + 97) + str(row + 1)
                if pos in self.pieces:
                    board_str += "W" if self.pieces[pos].color == "White" else "B"
                else:
                    board_str += "."
                board_str += "| "
            board_str += "\n"
        return board_str
```

